"""Helpers for CLI web-backed datasets, prompts, and evaluations."""
from __future__ import annotations

from dataclasses import dataclass
import re
from typing import Optional

import httpx

from zhanla_cli.eval_contract import (
    derive_expected_output as _derive_expected_output,
    derive_model_input as _derive_model_input,
    derive_model_response as _derive_model_response,
    stringify_value as _stringify_value_impl,
)
from zhanla_cli.writer import get_supabase_client


@dataclass
class WebDataset:
    dataset_id: str
    dataset_key: str
    dataset_name: str
    rows: list[dict]
    item_ids: list[str]


@dataclass
class WebAutorater:
    autorater_id: str
    autorater_key: str
    autorater_name: str


_UUID_PATTERN = re.compile(
    r"^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$",
    re.IGNORECASE,
)


class SdkListRouteUnavailable(RuntimeError):
    """Raised when the server doesn't expose the SDK list endpoints yet."""


def _stringify_value(value: object) -> str:
    return _stringify_value_impl(value)


def derive_model_input(row: dict) -> str:
    return _derive_model_input(row)


def derive_expected_output(row: dict) -> str:
    """Return the plain-text eval contract for expected output.

    Managed evaluate-only runs should always receive text fields. Structured
    dataset values are serialized here, and eval code is responsible for
    parsing JSON/YAML/plain text as needed.
    """
    return _derive_expected_output(row)


def derive_model_response(output: object) -> str:
    """Return the plain-text eval contract for model responses.

    Component outputs may remain structured internally for tracing, upload, and
    debugging, but the eval boundary is text-only. Evals should parse this
    string themselves if they want structured data.
    """
    return _derive_model_response(output)


def _looks_like_uuid(value: str) -> bool:
    return bool(_UUID_PATTERN.match(value.strip()))


def resolve_web_autorater(
    *,
    supabase_url: str,
    supabase_anon_key: str,
    access_token: str,
    autorater_key_or_id: str,
) -> WebAutorater:
    client = get_supabase_client(supabase_url, supabase_anon_key, access_token)
    identifier = autorater_key_or_id.strip()

    queries = [("key", identifier)]
    if _looks_like_uuid(identifier):
        queries = [("id", identifier), ("key", identifier)]

    for field, value in queries:
        result = (
            client.table("autoraters")
            .select("id,key,name")
            .eq(field, value)
            .limit(1)
            .execute()
        )
        rows = getattr(result, "data", None) or []
        if not rows:
            continue
        row = rows[0]
        return WebAutorater(
            autorater_id=row["id"],
            autorater_key=row.get("key") or identifier,
            autorater_name=row.get("name") or identifier,
        )

    raise RuntimeError(
        f"Autorater '{autorater_key_or_id}' not found. "
        "Run 'zhanla list autoraters' to see available autoraters."
    )


def fetch_web_dataset(
    *,
    supabase_url: str,
    supabase_anon_key: str,
    access_token: str,
    dataset_key_or_id: str,
) -> WebDataset:
    client = get_supabase_client(supabase_url, supabase_anon_key, access_token)
    identifier = dataset_key_or_id.strip()

    dataset_rows: list[dict] = []
    queries = [("key", identifier)]
    if _looks_like_uuid(identifier):
        queries = [("id", identifier), ("key", identifier)]

    for field, value in queries:
        dataset_result = (
            client.table("datasets")
            .select("id,key,name")
            .eq(field, value)
            .limit(1)
            .execute()
        )
        dataset_rows = getattr(dataset_result, "data", None) or []
        if dataset_rows:
            break

    if not dataset_rows:
        raise RuntimeError(
            f"Dataset '{dataset_key_or_id}' not found. "
            "Run 'zhanla list datasets' to see available datasets."
        )

    dataset_id = dataset_rows[0]["id"]

    item_result = (
        client.table("dataset_items")
        .select("id,input,is_active,created_at")
        .eq("dataset_id", dataset_id)
        .eq("is_active", True)
        .execute()
    )
    raw_items = getattr(item_result, "data", None) or []
    if not raw_items:
        dataset_name = dataset_rows[0].get("name") or dataset_key_or_id
        raise RuntimeError(
            f"Dataset '{dataset_name}' exists but has no rows. "
            "Add items via the web app or upload a local dataset file with --dataset."
        )

    sorted_items = sorted(raw_items, key=lambda row: row.get("created_at") or "")
    return WebDataset(
        dataset_id=dataset_rows[0]["id"],
        dataset_key=dataset_rows[0].get("key") or identifier,
        dataset_name=dataset_rows[0].get("name") or identifier,
        rows=[item.get("input") or {} for item in sorted_items],
        item_ids=[item["id"] for item in sorted_items],
    )


def fetch_web_prompt(
    *,
    supabase_url: str,
    supabase_anon_key: str,
    access_token: str,
    prompt_key_or_id: str,
) -> dict:
    """Fetch a web-managed component config by family key or legacy definition id.

    `--web-config` is backed by component definitions, but this helper keeps
    the historical function name so existing CLI call sites and tests do not
    need to change in lockstep.
    """
    client = get_supabase_client(supabase_url, supabase_anon_key, access_token)
    identifier = prompt_key_or_id.strip()

    if _looks_like_uuid(identifier):
        result = (
            client.table("component_definitions")
            .select("id,name,family_id")
            .eq("id", identifier)
            .limit(1)
            .execute()
        )
        rows = getattr(result, "data", None) or []
        if not rows:
            raise RuntimeError(
                f"Component '{prompt_key_or_id}' not found. "
                "Run 'zhanla list components' to see available component keys."
            )
        row = rows[0]
        family_id = row.get("family_id")
        uuid_component_type = None
        if family_id:
            family_result = (
                client.table("component_families")
                .select("component_type")
                .eq("id", family_id)
                .limit(1)
                .execute()
            )
            family_rows_uuid = getattr(family_result, "data", None) or []
            if family_rows_uuid:
                uuid_component_type = family_rows_uuid[0].get("component_type")
        return {
            "id": row["id"],
            "slug": row.get("name") or identifier,
            "component_family_id": family_id,
            "component_type": uuid_component_type,
        }

    families_result = (
        client.table("component_families")
        .select("id,key,component_type")
        .eq("key", identifier)
        .in_("component_type", ["agent", "skill", "tool", "orchestration", "llm_processor"])
        .execute()
    )
    family_rows = getattr(families_result, "data", None) or []
    if not family_rows:
        raise RuntimeError(
            f"Component '{identifier}' not found. "
            "Run 'zhanla list components' to see available component keys."
        )
    if len(family_rows) > 1:
        component_types = ", ".join(str(row.get("component_type") or "") for row in family_rows)
        raise RuntimeError(
            f"Component key '{identifier}' is ambiguous — it matches multiple types: {component_types}. "
            "Use 'zhanla list components --name {identifier}' to inspect, "
            "or pass the component UUID directly."
        )

    family_id = family_rows[0]["id"]
    family_component_type = family_rows[0].get("component_type")
    prod_result = (
        client.table("component_definitions")
        .select("id,name,family_id,version,is_prod")
        .eq("family_id", family_id)
        .eq("is_prod", True)
        .limit(1)
        .execute()
    )
    prod_rows = getattr(prod_result, "data", None) or []
    if not prod_rows:
        latest_result = (
            client.table("component_definitions")
            .select("id,name,family_id,version,is_prod")
            .eq("family_id", family_id)
            .order("version", desc=True)
            .limit(1)
            .execute()
        )
        prod_rows = getattr(latest_result, "data", None) or []

    if not prod_rows:
        raise RuntimeError(
            f"Component '{identifier}' exists but has no versions. "
            "Create and promote a version via the web app before running with --web-config."
        )

    row = prod_rows[0]
    return {
        "id": row["id"],
        "slug": row.get("name") or identifier,
        "component_family_id": row.get("family_id"),
        "component_key": identifier,
        "component_type": family_component_type,
    }


def _sdk_headers(*, access_token: str, org_id: Optional[str]) -> dict[str, str]:
    headers = {"Authorization": f"Bearer {access_token}"}
    if org_id:
        headers["X-Org-Id"] = org_id
    return headers


def _extract_http_error(response: httpx.Response) -> str:
    try:
        payload = response.json()
    except ValueError:
        payload = None

    if isinstance(payload, dict):
        for key in ("error", "message", "detail"):
            value = payload.get(key)
            if isinstance(value, str) and value.strip():
                return value.strip()

    text = response.text.strip()
    return text or response.reason_phrase or "Request failed"


def _request_sdk_list(
    *,
    base_url: str,
    access_token: str,
    org_id: Optional[str],
    path: str,
    result_key: str,
    params: dict[str, str],
) -> list[dict]:
    try:
        response = httpx.get(
            f"{base_url.rstrip('/')}{path}",
            params=params,
            headers=_sdk_headers(access_token=access_token, org_id=org_id),
            timeout=30.0,
        )
    except httpx.RequestError as exc:
        raise SdkListRouteUnavailable(
            f"SDK list endpoint request failed for {path}: {exc}"
        ) from exc
    if response.status_code in {404, 405}:
        raise SdkListRouteUnavailable(
            f"SDK list endpoint is not available at {path}"
        )
    if not response.is_success:
        detail = _extract_http_error(response)
        raise RuntimeError(f"HTTP {response.status_code}: {detail}")

    payload = response.json()
    rows = payload.get(result_key)
    if not isinstance(rows, list):
        raise RuntimeError(f"Unexpected response from {path}: {payload}")
    return [row for row in rows if isinstance(row, dict)]


def list_web_datasets(
    *,
    base_url: str,
    access_token: str,
    org_id: Optional[str] = None,
    owner_type: Optional[str] = None,
    owner_id: Optional[str] = None,
    name: Optional[str] = None,
) -> list[dict]:
    params = {
        key: value
        for key, value in {
            "owner_type": owner_type,
            "owner_id": owner_id,
            "name": name,
        }.items()
        if value is not None
    }
    return _request_sdk_list(
        base_url=base_url,
        access_token=access_token,
        org_id=org_id,
        path="/api/v1/sdk/datasets",
        result_key="datasets",
        params=params,
    )


def list_web_autoraters(
    *,
    base_url: str,
    access_token: str,
    org_id: Optional[str] = None,
    owner_type: Optional[str] = None,
    owner_id: Optional[str] = None,
    name: Optional[str] = None,
) -> list[dict]:
    params = {
        key: value
        for key, value in {
            "owner_type": owner_type,
            "owner_id": owner_id,
            "name": name,
        }.items()
        if value is not None
    }
    return _request_sdk_list(
        base_url=base_url,
        access_token=access_token,
        org_id=org_id,
        path="/api/v1/sdk/autoraters",
        result_key="autoraters",
        params=params,
    )


def start_evaluate_only(
    *,
    base_url: str,
    access_token: str,
    autorater_id: str,
    items: list[dict],
    dataset_id: Optional[str] = None,
    model_endpoint: Optional[str] = None,
    org_id: Optional[str] = None,
) -> dict:
    """Start only step 2 of the managed autorater flow.

    The caller already computed component responses locally and uploads them as
    plain-text eval inputs. The server only runs the managed autorater against
    those uploaded responses.
    """
    payload: dict = {
        "items": items,
    }
    if _looks_like_uuid(autorater_id):
        payload["autorater_id"] = autorater_id
    else:
        payload["autorater_key"] = autorater_id
    if dataset_id is not None:
        if _looks_like_uuid(dataset_id):
            payload["dataset_id"] = dataset_id
        else:
            payload["dataset_key"] = dataset_id
    if model_endpoint is not None:
        payload["model_endpoint"] = model_endpoint

    headers: dict = {"Authorization": f"Bearer {access_token}"}
    if org_id:
        headers["X-Org-Id"] = org_id

    response = httpx.post(
        f"{base_url}/api/v1/sdk/evaluations/evaluate-only/start",
        json=payload,
        headers=headers,
        timeout=30.0,
    )
    if not response.is_success:
        try:
            detail = response.json().get("error", response.text)
        except Exception:
            detail = response.text
        raise RuntimeError(f"HTTP {response.status_code}: {detail}")
    data = response.json()
    if "runId" not in data:
        raise RuntimeError(f"Unexpected response from evaluate-only start: {data}")
    return data
